"use strict";(globalThis.webpackChunktanyaacjain_github_io=globalThis.webpackChunktanyaacjain_github_io||[]).push([[6967],{965:(e,n,t)=>{t.r(n),t.d(n,{assets:()=>l,contentTitle:()=>o,default:()=>d,frontMatter:()=>s,metadata:()=>r,toc:()=>h});var i=t(4848),a=t(8453);const s={title:"ALiAS - Building a Tech Community Rooted in Ownership",tags:["reflections"],authors:"tanya",date:new Date("2020-01-15T00:00:00.000Z")},o="Building a Community Rooted in Ownership",r={permalink:"/writings/alias",source:"@site/writings/alias.mdx",title:"ALiAS - Building a Tech Community Rooted in Ownership",description:"Fall 2016",date:"2020-01-15T00:00:00.000Z",tags:[{inline:!1,label:"Reflections",permalink:"/writings/tags/reflections",description:"Things reflected upon"}],readingTime:6.46,hasTruncateMarker:!1,authors:[{name:"Tanya Jain",title:"Author",url:"https://github.com/tanyaacjain",socials:{x:"tanyaacjain",github:"tanyaacjain"},imageURL:"https://github.com/tanyaacjain.png",key:"tanya"}],frontMatter:{title:"ALiAS - Building a Tech Community Rooted in Ownership",tags:["reflections"],authors:"tanya",date:"2020-01-15T00:00:00.000Z"},unlisted:!1,prevItem:{title:"Reliably Generating AI Code",permalink:"/writings/reliable-ai-coding"},nextItem:{title:"My Journey Into Tech",permalink:"/writings/starting-off-in-tech"}},l={authorsImageUrls:[void 0]},h=[{value:"Fall 2016",id:"fall-2016",level:2},{value:"Inception",id:"inception",level:2},{value:"Roles and Responsibilities",id:"roles-and-responsibilities",level:2},{value:"Growth and Milestones",id:"growth-and-milestones",level:2},{value:"Linux Study Group with Prof. Priya Ranjan",id:"linux-study-group-with-prof-priya-ranjan",level:2},{value:"Overcoming Challenges",id:"overcoming-challenges",level:2},{value:"Bridging Gaps",id:"bridging-gaps",level:2},{value:"Impact",id:"impact",level:2},{value:"Expansion",id:"expansion",level:2},{value:"Looking Ahead",id:"looking-ahead",level:2},{value:"Reflection",id:"reflection",level:2}];function c(e){const n={a:"a",em:"em",h2:"h2",img:"img",li:"li",p:"p",strong:"strong",table:"table",th:"th",thead:"thead",tr:"tr",ul:"ul",...(0,a.R)(),...e.components};return(0,i.jsxs)(i.Fragment,{children:[(0,i.jsx)(n.h2,{id:"fall-2016",children:"Fall 2016"}),"\n",(0,i.jsx)(n.p,{children:(0,i.jsx)(n.em,{children:"A Community Born from Necessity"})}),"\n",(0,i.jsx)(n.p,{children:"I was three weeks into university when I realized something was missing. The campus buzzed with tech clubs, sponsored by names everyone recognized (Mozilla, Microsoft, etc), but their calendars were filled with formals, branding events, and administrative formalities. Actual conversations about code, systems, and the open\u2011source philosophy were rare."}),"\n",(0,i.jsxs)(n.p,{children:["I wanted a space where computer scientists could simply\xa0",(0,i.jsx)(n.em,{children:"build"}),", share, and learn without hierarchy. A place where a first\u2011year student could sit beside someone who\u2019d been contributing in tech for years, and both would walk away having taught each other something."]}),"\n",(0,i.jsx)(n.h2,{id:"inception",children:"Inception"}),"\n",(0,i.jsx)(n.p,{children:"In ALiAS, what mattered first was the gathering. A few of us began meeting in empty classrooms, running installation fests, and talking late into the evening about kernels, pull requests, and why open source mattered. Shyam Saini and Shivam Rajput were there from the earliest conversations, confirming I wasn\u2019t alone. Over the next few months, others joined, each drawn by the same hunger for genuine technical community."}),"\n",(0,i.jsxs)(n.p,{children:["This is how ALiAS,  ",(0,i.jsx)(n.strong,{children:"Amity Linux Assistance Sapience"}),", was born. A name that captured the identity we were creating for tech enthusiasts\xa0who believed in open source, accessibility and exploration."]}),"\n",(0,i.jsx)(n.p,{children:"From those small beginnings, ALiAS grew into something larger than any of us expected. But the foundation was always the same: a flat, inclusive space where curiosity mattered more than credentials. Our vision was simple, to create an accessible environment where collaboration, knowledge sharing, and personal growth could happen naturally, without the barriers that often fragment student communities."}),"\n",(0,i.jsx)(n.h2,{id:"roles-and-responsibilities",children:"Roles and Responsibilities"}),"\n",(0,i.jsx)(n.p,{children:"A strong community needs structure to direct the immense energy sparked from enthusiasm. For this, ALiAS was designed around a flat hierarchy, deliberately avoiding rigid titles so that members could take ownership of areas aligned with their strengths. This approach allowed me to delegate strategically while ensuring that every aspect of the community received focused attention."}),"\n",(0,i.jsxs)(n.ul,{children:["\n",(0,i.jsxs)(n.li,{children:[(0,i.jsx)(n.strong,{children:"Community ethos and leadership"}),"\xa0\u2013 I entrusted key members to uphold the vision in day\u2011to\u2011day decisions, providing guidance while allowing them to lead in their own style."]}),"\n",(0,i.jsxs)(n.li,{children:[(0,i.jsx)(n.strong,{children:"Inclusivity and communication"}),"\xa0\u2013 I personally shaped the communication framework and inclusivity practices, setting the tone for how we onboarded members, handled conflict, and made sure every voice was heard."]}),"\n",(0,i.jsxs)(n.li,{children:[(0,i.jsx)(n.strong,{children:"Technical development"}),"\xa0\u2013 I established a technical mentorship structure, pairing experienced contributors with newcomers to maintain high code quality and encourage knowledge transfer."]}),"\n",(0,i.jsxs)(n.li,{children:[(0,i.jsx)(n.strong,{children:"Event logistics"}),"\xa0\u2013 I designed a workflow for planning and executing events, empowering members to run operations while I oversaw alignment with our long\u2011term goals."]}),"\n",(0,i.jsxs)(n.li,{children:[(0,i.jsx)(n.strong,{children:"Content and documentation"}),"\xa0\u2013 I created systems for documenting our work and creating accessible learning materials, ensuring that knowledge outlived any single event."]}),"\n",(0,i.jsxs)(n.li,{children:[(0,i.jsx)(n.strong,{children:"Outreach and partnerships"}),"\xa0\u2013 I led external engagement, connecting with industry mentors, faculty, and organizations to expand our network and bring new opportunities to the community."]}),"\n"]}),"\n",(0,i.jsx)(n.p,{children:"\u2800This structure gave each area the focused attention it needed while keeping the organization agile\u2014and it allowed me to scale my impact by enabling others to lead within clear guardrails."}),"\n",(0,i.jsx)(n.p,{children:(0,i.jsx)(n.img,{alt:"community",src:t(1208).A+"",width:"2048",height:"746"})}),"\n",(0,i.jsx)(n.h2,{id:"growth-and-milestones",children:"Growth and Milestones"}),"\n",(0,i.jsx)(n.p,{children:"From small workshops to large\u2011scale annual events like Hacktoberfest, I deliberately chose activities that would build both technical skills and a sense of shared purpose. Some of the initiatives I launched or led include:"}),"\n",(0,i.jsxs)(n.ul,{children:["\n",(0,i.jsxs)(n.li,{children:[(0,i.jsx)(n.strong,{children:"Monthly Linux Installation Fests"}),"\xa0\u2013 Introducing students to Linux and helping them get started with a powerful open\u2011source environment."]}),"\n",(0,i.jsxs)(n.li,{children:[(0,i.jsx)(n.strong,{children:"Daily Tech Meetups"}),"\xa0\u2013 Creating a regular forum for discussing the latest technological advancements and sharing insights across the community."]}),"\n",(0,i.jsxs)(n.li,{children:[(0,i.jsx)(n.strong,{children:"Community Calls"}),"\xa0\u2013 Establishing a rhythm of planning meetings to continually refine ALiAS\u2019s direction and expand its reach."]}),"\n",(0,i.jsxs)(n.li,{children:[(0,i.jsx)(n.strong,{children:"Specialized Study Groups"}),"\xa0\u2013 Organizing peer\u2011led groups in areas like frontend development and machine learning, with support from faculty collaborators."]}),"\n",(0,i.jsxs)(n.li,{children:[(0,i.jsxs)(n.strong,{children:["Annual ",(0,i.jsx)(n.a,{href:"https://hacktoberfest.digitalocean.com/",children:"Hacktoberfest"})," events"]}),"\xa0\u2013 Introducing students to open\u2011source contribution and helping them make their first pull requests in a supportive environment."]}),"\n"]}),"\n",(0,i.jsx)(n.p,{children:"\u2800Beyond events, I also drove the creation of a community blog\u2014a platform for members to share technical insights and experiences, which became a key tool for building our reputation beyond campus."}),"\n",(0,i.jsx)(n.p,{children:"These efforts did more than grow numbers; they created a culture where students felt empowered to lead their own initiatives. I made it a priority to identify emerging leaders and give them the space to run workshops, mentor peers, and eventually start their own chapters elsewhere."}),"\n",(0,i.jsx)(n.h2,{id:"linux-study-group-with-prof-priya-ranjan",children:"Linux Study Group with Prof. Priya Ranjan"}),"\n",(0,i.jsx)(n.p,{children:"One of the most rewarding collaborations came through Prof. Priya Ranjan, a Linux enthusiast in the Electrical and Electronics department who had been running weekend study groups for years. We began co\u2011organizing sessions that combined his deep technical expertise with ALiAS\u2019s growing community of learners. His ability to explain complex systems in simple terms left a lasting mark on how I thought about teaching and mentorship."}),"\n",(0,i.jsx)(n.p,{children:(0,i.jsx)(n.img,{alt:"Linux Study Group by Prof. Priya Ranjan",src:t(5517).A+"",width:"800",height:"274"})}),"\n",(0,i.jsx)(n.h2,{id:"overcoming-challenges",children:"Overcoming Challenges"}),"\n",(0,i.jsx)(n.p,{children:"No community\u2011building journey is without obstacles. Navigating university bureaucracy, engaging a broader student base in open\u2011source contributions, and addressing gaps in participation all required persistence and adaptability. Each challenge became an opportunity to refine my approach\u2014whether it was learning how to negotiate with administrators or redesigning outreach strategies to reach students who hadn\u2019t yet found a technical home."}),"\n",(0,i.jsx)(n.h2,{id:"bridging-gaps",children:"Bridging Gaps"}),"\n",(0,i.jsxs)(n.p,{children:[(0,i.jsx)(n.strong,{children:"Enhancing Women\u2019s Participation in Tech"}),"\nDespite our growth, the gender ratio in tech remained skewed. Of the founding members, only two of us were women, and participation reflected that imbalance. I knew that passive inclusion wasn\u2019t enough\u2014so I initiated targeted efforts to change the dynamic."]}),"\n",(0,i.jsx)(n.p,{children:"I organized workshops and events specifically designed to welcome women into tech spaces, including Women\u2019s Day tech talks featuring prominent contributors like Shivani Bhardawaj of LinuxChix India."}),"\n",(0,i.jsx)(n.p,{children:"Beyond events, I started a personal mentorship program where I guided women students through career choices, skill development, and navigating the tech landscape. These efforts significantly boosted female participation and, more importantly, brought diverse perspectives into the heart of the community."}),"\n",(0,i.jsx)("div",{className:"img-tb",children:(0,i.jsx)(n.table,{children:(0,i.jsx)(n.thead,{children:(0,i.jsxs)(n.tr,{children:[(0,i.jsx)(n.th,{children:(0,i.jsx)(n.img,{alt:"ALiAS Women Participation",src:t(4479).A+"",width:"1015",height:"562"})}),(0,i.jsx)(n.th,{children:(0,i.jsx)(n.img,{alt:"ALiAS Women Participation",src:t(5455).A+"",width:"1296",height:"718"})})]})})})}),"\n",(0,i.jsx)(n.h2,{id:"impact",children:"Impact"}),"\n",(0,i.jsx)(n.p,{children:"The impact of these efforts became visible in tangible ways. ALiAS was recognized as the most active tech club on campus\u2014a distinction that carried weight when I later advocated for curriculum changes. Working with faculty and administration, I helped make the case for introducing Python into formal coursework, a change that benefited students across departments."}),"\n",(0,i.jsx)(n.h2,{id:"expansion",children:"Expansion"}),"\n",(0,i.jsxs)(n.p,{children:[(0,i.jsx)(n.strong,{children:"The Rise of ALiAS Chapters"}),"\nThe model we built\u2014a flat, inclusive, student\u2011led community\u2014proved replicable. When students from Amity University, Lucknow, expressed interest in starting their own chapter, I provided guidance, shared our resources, and helped them adapt the framework to their context. That first chapter became a blueprint, and soon ALiAS chapters began emerging across India, each carrying forward the same ethos of open\u2011source advocacy and community\u2011driven learning."]}),"\n",(0,i.jsx)(n.h2,{id:"looking-ahead",children:"Looking Ahead"}),"\n",(0,i.jsx)(n.p,{children:"Today, ALiAS has grown to over 4,000 members across multiple chapters. Students who once attended their first installation fest now contribute to major open\u2011source projects, speak at conferences, and mentor the next generation. The mentorship programs I helped establish, along with initiatives like GSoC sessions, continue to guide new waves of technologists."}),"\n",(0,i.jsx)(n.p,{children:(0,i.jsx)(n.img,{alt:"audience",src:t(1989).A+"",width:"2048",height:"1365"})}),"\n",(0,i.jsx)(n.h2,{id:"reflection",children:"Reflection"}),"\n",(0,i.jsx)(n.p,{children:"Looking back, building ALiAS taught me that sustainable communities are built on clear systems, not just enthusiasm. I learned how to design structures that empower others while maintaining strategic direction\u2014a skill I now rely on in everything I do. More than anything, I saw that when you give people ownership and hold a clear vision, they will surprise you with what they can achieve."}),"\n",(0,i.jsx)(n.p,{children:"This journey also deepened my conviction that technology is at its best when it is collaborative, inclusive, and rooted in genuine curiosity. Those principles continue to shape how I approach problems, lead teams, and contribute to the open\u2011source ecosystem. ALiAS was never just a club\u2014it was a proving ground for the kind of technologist and leader I wanted to become."})]})}function d(e={}){const{wrapper:n}={...(0,a.R)(),...e.components};return n?(0,i.jsx)(n,{...e,children:(0,i.jsx)(c,{...e})}):c(e)}},1208:(e,n,t)=>{t.d(n,{A:()=>i});const i=t.p+"assets/images/community-067b488d1c8c288fe6b0113fd90f87e8.jpeg"},1989:(e,n,t)=>{t.d(n,{A:()=>i});const i=t.p+"assets/images/audience-964712f02b3fcd080be2892494f3775c.jpeg"},4479:(e,n,t)=>{t.d(n,{A:()=>i});const i=t.p+"assets/images/womens-day-24ac5e652e29028ddc8b5cdf1c81e673.jpeg"},5455:(e,n,t)=>{t.d(n,{A:()=>i});const i=t.p+"assets/images/womens-day2-087a52427975eb83b7011e89071c31eb.jpeg"},5517:(e,n,t)=>{t.d(n,{A:()=>i});const i=t.p+"assets/images/linux-study-group-ef5db91e516679e09ab74ab090c5ab43.jpeg"},8453:(e,n,t)=>{t.d(n,{R:()=>o,x:()=>r});var i=t(6540);const a={},s=i.createContext(a);function o(e){const n=i.useContext(s);return i.useMemo(function(){return"function"==typeof e?e(n):{...n,...e}},[n,e])}function r(e){let n;return n=e.disableParentContext?"function"==typeof e.components?e.components(a):e.components||a:o(e.components),i.createElement(s.Provider,{value:n},e.children)}}}]);